{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select Pelvic CT Volume",
      "simple": "Choose the Pelvic Volume from the Input CT Volume selector.",
      "detailed": "This is the starting point of the planning workflow. The pelvic CT scan provides the anatomical basis for all subsequent segmentation, fracture analysis, and reduction planning. Select the appropriate volume from the dropdown to proceed."
    },
    {
      "step_id": "cb_step_2",
      "title": "Segment Pelvis",
      "simple": "Click the 'Run Step 1: Segment Pelvis' button.",
      "detailed": "This step automatically segments the pelvic bone from the CT volume using an AI-based algorithm. A clean pelvic segmentation is essential for identifying fracture fragments and planning reduction. After clicking, wait for processing to complete."
    },
    {
      "step_id": "cb_step_3",
      "title": "Segment Fractures",
      "simple": "Click the 'Run Step 2: Segment Fractures' button.",
      "detailed": "This step identifies and separates individual fracture fragments from the pelvic segmentation. Accurate fragment segmentation is critical for later reduction planning and screw placement. The algorithm will label each fragment based on the fracture pattern."
    },
    {
      "step_id": "cb_step_4",
      "title": "Exclude Fragments from Planning",
      "simple": "Untick any fragments you wish to exclude from the planning process.",
      "detailed": "You may disable fragments that are not relevant for reduction, such as small avulsion fragments or fractures that will not be surgically addressed. Excluding unnecessary fragments simplifies the reduction plan and focuses on the clinically important pieces. Click 'Done' when finished."
    },
    {
      "step_id": "cb_step_5",
      "title": "Generate Reduction Template",
      "simple": "Click the 'Run Step 3: Generate Template' button.",
      "detailed": "This step creates an initial template of the intended reduction, aligning the main pelvic fragments based on anatomical landmarks. The template serves as a starting point for the registration and fine-tuning in the next step. Processing may take a moment."
    },
    {
      "step_id": "cb_step_6",
      "title": "Register and Reduce",
      "simple": "Click the 'Run Step 4: Register _Reduce' button.",
      "detailed": "This step performs automated registration of fracture fragments to achieve an anatomical reduction. The algorithm aligns fragments relative to the intact pelvic template, approximating the correct position. Review the result; further manual adjustment may be needed."
    },
    {
      "step_id": "cb_step_7",
      "title": "Refine Reduction",
      "simple": "Click the 'Run Step 4: Register _Reduce' button again if the initial reduction needs improvement.",
      "detailed": "Running the reduction step again can refine the alignment, particularly for complex fractures. You can repeat this step multiple times until you are satisfied with the fragment alignment."
    },
    {
      "step_id": "cb_step_8",
      "title": "Decide on Manual Adjustment",
      "simple": "Decide if you need to manually adjust a fragment: tick the checkbox for Yes, or untick to skip to the next step.",
      "detailed": "If the automated reduction result is not fully satisfactory, you can manually adjust individual fragments. For well-aligned reductions, you can proceed directly to screw planning without manual intervention."
    },
    {
      "step_id": "cb_step_9",
      "title": "Select Fragment to Adjust",
      "simple": "Choose the fragment that needs adjustment from the 'Fragment' selection box.",
      "detailed": "Identify the fracture fragment that requires fine-tuning. Selecting it here will allow you to manipulate its position and rotation in the next step. Only one fragment can be adjusted at a time."
    },
    {
      "step_id": "cb_step_10",
      "title": "Manually Adjust Fragment Position",
      "simple": "Use the transform tools to move and rotate the selected fragment to its correct anatomical position.",
      "detailed": "Carefully reposition the fragment relative to the pelvis using the interactive transform tools. This step is important for achieving the best possible reduction before finalizing screw plans. Once satisfied, click 'Done' to confirm."
    },
    {
      "step_id": "cb_step_11",
      "title": "Apply Fragment Adjustments",
      "simple": "Click the 'Apply adjustments' button to commit your manual fragment repositioning.",
      "detailed": "This button registers the manual transformation back into the reduction plan, updating the fragment's position. The adjusted reduction is then used for screw planning."
    },
    {
      "step_id": "cb_step_12",
      "title": "Plan Screws",
      "simple": "Click the 'Plan Screws' button to automatically generate screw trajectories.",
      "detailed": "This step uses the reduced pelvic model to propose optimal screw paths for fracture fixation. The algorithm considers bone geometry and safe corridors to suggest screw positions. Review the proposed screws; they may be edited later if needed."
    },
    {
      "step_id": "cb_step_13",
      "title": "Decide on Screw Editing",
      "simple": "Tick the 'Edit Screw trajectories' checkbox if you want to adjust the planned screws, or untick to finish.",
      "detailed": "If the automatically generated screw trajectories need refinement (e.g., to avoid a fracture line or improve bone purchase), you can manually edit them. Otherwise, the planning is complete."
    },
    {
      "step_id": "cb_step_14",
      "title": "Adjust Screw Trajectories",
      "simple": "Use the transform tools to adjust the position and rotation of the screw trajectories as needed.",
      "detailed": "Fine-tune each screw's entry point, direction, and depth based on your surgical judgment. This ensures safe and effective fixation. Click 'Done' when adjustments are satisfactory."
    },
    {
      "step_id": "cb_step_15",
      "title": "Regenerate Screw from Edited Lines",
      "simple": "Click the 'Regenerate screw from edited lines' button to update the screw models based on your manual adjustments.",
      "detailed": "This button recalculates the screw model geometry to match the new trajectory lines you defined. After regeneration, the updated screws are ready for final review."
    },
    {
      "step_id": "cb_step_16",
      "title": "Finalize and Finish",
      "simple": "Untick the 'Edit Screw trajectories' checkbox to exit editing mode.",
      "detailed": "Disabling screw editing finalizes the screw plan. The reduction and screw plan are now complete and can be used for surgical reference or export."
    }
  ]
}
